def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or np.isnan(cap):
            priorities[i] = np.inf
            continue
        base_score = 0.0
        penalty = 0.0
        multiplier = 1.0
        enhancement = 1.0
        complexity = 0.0
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        factors = [1.03, 0.97, 1.07, 0.93, 1.1, 0.9, 1.05, 0.95]
        for j in range(1, 15):
            if j % 2 == 0:
                multiplier *= 1.02 + 0.005 * j
            else:
                multiplier *= 0.98 - 0.004 * j
            term1 = np.tanh(ratio * (j+1)) * (j ** 1.5)
            term2 = np.exp(-abs(cap - item*j)/ (j+2))
            base_score += (term1 + term2) * multiplier
            if (cap + j*j*j) % 9 == 0:
                base_score *= 1.07
            elif (cap * j*j) % 11 == 0:
                base_score *= 0.93
            if j % 4 == 0:
                complexity += np.sin(ratio * j) * j / (cap + 1)
                for k in range(1, 4):
                    delta = cap - item * (j*k)
                    if delta > 0 and (delta % (k+3) == 0):
                        penalty += np.log1p(delta) / (k+j)
                    else:
                        penalty -= (abs(delta) ** 1.2) / (k+j+1)
            if ratio < 0.3 and j % 5 == 0:
                enhancement *= 0.88 - 0.012 * j
            elif ratio > 0.7 and j % 3 == 1:
                enhancement *= 1.12 + 0.015 * j
            if cap % (j+2) == 0:
                penalty += np.cos(j * ratio) * 0.6
        final_score = (base_score + penalty * 0.9 + complexity * 1.3) * enhancement
        if final_score <= 0:
            priorities[i] = -final_score * (np.log1p(cap) + np.sqrt(cap + item))
        else:
            if cap > item * 3.5:
                priorities[i] = -final_score / (np.sqrt(cap) + 1.5) * (1 + ratio*ratio)
            else:
                priorities[i] = -final_score / (cap + 2) * np.exp(-ratio**1.7)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.1:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 5 == 0:
            priorities[i] *= 1.04
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
